     1→/**
     2→ * CortexBuild Ultimate — Universal Data Hooks
     3→ * Uses React Query for caching, background refresh, and optimistic updates.
     4→ */
     5→import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
     6→import { toast } from 'sonner';
     7→import {
     8→  projectsApi, invoicesApi, teamApi, safetyApi, rfisApi, changeOrdersApi,
     9→  ramsApi, cisApi, equipmentApi, subcontractorsApi, timesheetsApi,
    10→  documentsApi, tendersApi, dailyReportsApi, meetingsApi, materialsApi,
    11→  punchListApi, inspectionsApi, contactsApi, riskRegisterApi, purchaseOrdersApi,
    12→} from '../services/api';
    13→
    14→type Row = Record<string, unknown>;
    15→
    16→// ─── Generic hook factory ─────────────────────────────────────────────────────
    17→
    18→function makeHooks<T>(key: string, api: {
    19→  getAll: () => Promise<T[]>;
    20→  create: (data: Row) => Promise<T | null>;
    21→  update: (id: string, data: Row) => Promise<T | null>;
    22→  delete: (id: string) => Promise<void>;
    23→}) {
    24→  function useList() {
    25→    return useQuery<T[]>({
    26→      queryKey: [key],
    27→      queryFn: api.getAll,
    28→      staleTime: 30_000, // 30 s
    29→    });
    30→  }
    31→
    32→  function useCreate() {
    33→    const qc = useQueryClient();
    34→    return useMutation({
    35→      mutationFn: (data: Row) => api.create(data),
    36→      onSuccess: () => {
    37→        qc.invalidateQueries({ queryKey: [key] });
    38→        toast.success('Record created successfully');
    39→      },
    40→      onError: (e: Error) => toast.error(e.message),
    41→    });
    42→  }
    43→
    44→  function useUpdate() {
    45→    const qc = useQueryClient();
    46→    return useMutation({
    47→      mutationFn: ({ id, data }: { id: string; data: Row }) => api.update(id, data),
    48→      onSuccess: () => {
    49→        qc.invalidateQueries({ queryKey: [key] });
    50→        toast.success('Record updated');
    51→      },
    52→      onError: (e: Error) => toast.error(e.message),
    53→    });
    54→  }
    55→
    56→  function useDelete() {
    57→    const qc = useQueryClient();
    58→    return useMutation({
    59→      mutationFn: (id: string) => api.delete(id),
    60→      onSuccess: () => {
    61→        qc.invalidateQueries({ queryKey: [key] });
    62→        toast.success('Record deleted');
    63→      },
    64→      onError: (e: Error) => toast.error(e.message),
    65→    });
    66→  }
    67→
    68→  return { useList, useCreate, useUpdate, useDelete };
    69→}
    70→
    71→// ─── Exported hooks ───────────────────────────────────────────────────────────
    72→
    73→export const useProjects       = makeHooks('projects',       projectsApi);
    74→export const useInvoices       = makeHooks('invoices',       invoicesApi);
    75→export const useTeam           = makeHooks('team',           teamApi);
    76→export const useSafety         = makeHooks('safety',         safetyApi);
    77→export const useRFIs           = makeHooks('rfis',           rfisApi);
    78→export const useChangeOrders   = makeHooks('change_orders',  changeOrdersApi);
    79→export const useRAMS           = makeHooks('rams',           ramsApi);
    80→export const useCIS            = makeHooks('cis',            cisApi);
    81→export const useEquipment      = makeHooks('equipment',      equipmentApi);
    82→export const useSubcontractors = makeHooks('subcontractors', subcontractorsApi);
    83→export const useTimesheets     = makeHooks('timesheets',     timesheetsApi);
    84→export const useDocuments      = makeHooks('documents',      documentsApi);
    85→export const useTenders        = makeHooks('tenders',        tendersApi);
    86→export const useDailyReports   = makeHooks('daily_reports',  dailyReportsApi);
    87→export const useMeetings       = makeHooks('meetings',       meetingsApi);
    88→export const useMaterials      = makeHooks('materials',      materialsApi);
