// Module: Dashboard — CortexBuild Ultimate
import { useState } from 'react';
import {
  TrendingUp, TrendingDown, FolderOpen, HardHat, FileText, ShieldCheck,
  MessageSquare, AlertCircle, Activity, CheckCircle2, PoundSterling,
  ArrowRight, BarChart3, Clock, Zap,
} from 'lucide-react';
import {
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  PieChart, Pie, Cell, Legend,
} from 'recharts';
import {
  useProjects, useInvoices, useTeam, useSafety, useRFIs, useDailyReports,
} from '../../hooks/useData';
import type { Module } from '../../types';
import clsx from 'clsx';

type AnyRow = Record<string, unknown>;

interface DashboardProps {
  setModule: (m: Module) => void;
}

const MONTH_REVENUE: { month: string; revenue: number; costs: number; profit: number }[] = [
  { month: 'Sep', revenue: 485000, costs: 342000, profit: 143000 },
  { month: 'Oct', revenue: 612000, costs: 445000, profit: 167000 },
  { month: 'Nov', revenue: 534000, costs: 378000, profit: 156000 },
  { month: 'Dec', revenue: 298000, costs: 225000, profit: 73000 },
  { month: 'Jan', revenue: 721000, costs: 512000, profit: 209000 },
  { month: 'Feb', revenue: 856000, costs: 601000, profit: 255000 },
  { month: 'Mar', revenue: 943000, costs: 648000, profit: 295000 },
];

const STATUS_COLORS: Record<string, string> = {
  active: '#22c55e',
  planning: '#3b82f6',
  on_hold: '#f59e0b',
  completed: '#10b981',
  archived: '#6b7280',
};

function fmtMoney(n: number) {
  if (n >= 1_000_000) return `£${(n / 1_000_000).toFixed(2)}M`;
  if (n >= 1_000) return `£${(n / 1_000).toFixed(0)}K`;
  return `£${n.toLocaleString()}`;
}

const QUICK_ACTIONS: { label: string; description: string; icon: React.ElementType; module: Module; color: string; bg: string }[] = [
  { label: 'Projects', description: 'View all projects', icon: FolderOpen, module: 'projects', color: 'text-blue-400', bg: 'bg-blue-500/10 border-blue-700/40 hover:border-blue-500/60' },
  { label: 'Invoicing', description: 'Manage invoices', icon: FileText, module: 'invoicing', color: 'text-orange-400', bg: 'bg-orange-500/10 border-orange-700/40 hover:border-orange-500/60' },
  { label: 'Safety', description: 'Safety & incidents', icon: ShieldCheck, module: 'safety', color: 'text-emerald-400', bg: 'bg-emerald-500/10 border-emerald-700/40 hover:border-emerald-500/60' },
  { label: 'RFIs', description: 'Open requests', icon: MessageSquare, module: 'rfis', color: 'text-purple-400', bg: 'bg-purple-500/10 border-purple-700/40 hover:border-purple-500/60' },
  { label: 'Teams', description: 'Team members', icon: HardHat, module: 'teams', color: 'text-yellow-400', bg: 'bg-yellow-500/10 border-yellow-700/40 hover:border-yellow-500/60' },
  { label: 'Reports', description: 'Daily site reports', icon: Activity, module: 'daily-reports', color: 'text-teal-400', bg: 'bg-teal-500/10 border-teal-700/40 hover:border-teal-500/60' },
];

export function Dashboard({ setModule }: DashboardProps) {
  const [_activeProject, setActiveProject] = useState<string | null>(null);

  const { data: rawProjects = [], isLoading: projLoading } = useProjects.useList();
  const { data: rawInvoices = [], isLoading: invLoading } = useInvoices.useList();
  const { data: rawTeam = [] } = useTeam.useList();
  const { data: rawSafety = [] } = useSafety.useList();
  const { data: rawRFIs = [] } = useRFIs.useList();
  const { data: rawReports = [] } = useDailyReports.useList();

  const projects = rawProjects as AnyRow[];
  const invoices = rawInvoices as AnyRow[];
  const team = rawTeam as AnyRow[];
  const safety = rawSafety as AnyRow[];
  const rfis = rawRFIs as AnyRow[];
  const reports = rawReports as AnyRow[];

  // KPI Calculations
  const activeProjects = projects.filter(p => p.status === 'active');
  const now = new Date();
  const monthStart = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0];
  const revenueThisMonth = invoices
    .filter(i => i.status === 'paid' && String(i.issueDate ?? i.issue_date ?? '') >= monthStart)
    .reduce((s, i) => s + Number(i.amount ?? 0), 0);
  const workersOnSite = team.filter(m => m.status === 'on_site' || m.status === 'active').length;
  const openRFIs = rfis.filter(r => r.status === 'open' || r.status === 'pending').length;
  const openIncidents = safety.filter(s => s.status === 'open' || s.status === 'investigating').length;
  const totalProjectValue = projects.reduce((s, p) => s + Number(p.contractValue ?? p.contract_value ?? 0), 0);

  // Project status distribution for pie chart
  const statusCounts: Record<string, number> = {};
  projects.forEach(p => {
    const s = String(p.status ?? 'unknown');
    statusCounts[s] = (statusCounts[s] ?? 0) + 1;
  });
  const pieData = Object.entries(statusCounts).map(([name, value]) => ({ name, value }));

  // Recent activity feed
  type FeedItem = { label: string; time: string; dot: string; sortKey: string };
  const feed: FeedItem[] = [];

  invoices.slice(0, 4).forEach(inv => {
    const status = String(inv.status ?? '');
    const date = String(inv.issueDate ?? inv.issue_date ?? '');
    feed.push({
      label: `Invoice ${String(inv.number ?? '')} — ${String(inv.client ?? '')} (${status})`,
      time: date,
      dot: status === 'paid' ? 'bg-green-400' : status === 'overdue' ? 'bg-red-400' : 'bg-blue-400',
      sortKey: date,
    });
  });

  rfis.filter(r => r.status === 'open' || r.status === 'pending').slice(0, 3).forEach(rfi => {
    const date = String(rfi.submittedDate ?? rfi.submitted_date ?? '');
    feed.push({
      label: `RFI ${String(rfi.number ?? '')} — ${String(rfi.subject ?? '')}`,
      time: date,
      dot: 'bg-purple-400',
      sortKey: date,
    });
  });

  safety.filter(s => s.status === 'open' || s.status === 'investigating').slice(0, 2).forEach(inc => {
    const date = String(inc.date ?? '');
    feed.push({
      label: `Safety: ${String(inc.title ?? '')} — ${String(inc.project ?? '')}`,
      time: date,
      dot: String(inc.severity ?? '') === 'serious' || String(inc.severity ?? '') === 'fatal' ? 'bg-red-400' : 'bg-yellow-400',
      sortKey: date,
    });
  });

  reports.slice(0, 2).forEach(r => {
    const date = String(r.date ?? '');
    feed.push({
      label: `Daily report — ${String(r.project ?? '')} by ${String(r.preparedBy ?? r.prepared_by ?? '')}`,
      time: date,
      dot: 'bg-emerald-400',
      sortKey: date,
    });
  });

  const recentActivity = feed
    .filter(f => f.sortKey)
    .sort((a, b) => (b.sortKey > a.sortKey ? 1 : -1))
    .slice(0, 7)
    .map(f => {
      const diff = Math.floor((Date.now() - new Date(f.time).getTime()) / 86400000);
      const timeLabel = isNaN(diff) ? '' : diff === 0 ? 'Today' : diff === 1 ? 'Yesterday' : `${diff}d ago`;
      return { ...f, timeLabel };
    });

  const isLoading = projLoading || invLoading;

  const kpiCards = [
    {
      label: 'Active Projects',
      value: isLoading ? '—' : String(activeProjects.length),
      sub: `${projects.length} total`,
      icon: FolderOpen,
      iconBg: 'bg-blue-500/15',
      iconColor: 'text-blue-400',
      trend: null,
    },
    {
      label: 'Revenue This Month',
      value: isLoading ? '—' : fmtMoney(revenueThisMonth),
      sub: `${fmtMoney(totalProjectValue)} pipeline`,
      icon: PoundSterling,
      iconBg: 'bg-orange-500/15',
      iconColor: 'text-orange-400',
      trend: '+12.4%',
    },
    {
      label: 'Workers On Site',
      value: isLoading ? '—' : String(workersOnSite),
      sub: `${team.length} team total`,
      icon: HardHat,
      iconBg: 'bg-green-500/15',
      iconColor: 'text-green-400',
      trend: null,
    },
    {
      label: 'Open RFIs',
      value: isLoading ? '—' : String(openRFIs),
      sub: `${rfis.length} total`,
      icon: MessageSquare,
      iconBg: openRFIs > 0 ? 'bg-red-500/15' : 'bg-emerald-500/15',
      iconColor: openRFIs > 0 ? 'text-red-400' : 'text-emerald-400',
      trend: null,
    },
  ];

  return (
    <div className="h-full overflow-y-auto bg-gray-950 p-6 space-y-6">
      {/* Welcome Banner */}
      <div className="rounded-2xl border border-orange-800/30 bg-gradient-to-r from-orange-900/30 via-gray-900 to-gray-900 p-6">
        <div className="flex items-start justify-between">
          <div>
            <h1 className="text-2xl font-bold text-white">Good morning, Adrian 👋</h1>
            <p className="mt-1 text-sm text-gray-400">
              Saturday, 21 March 2026 &nbsp;•&nbsp; CortexBuild Ltd
            </p>
          </div>
          <div className="flex items-center gap-2 rounded-xl border border-orange-700/30 bg-orange-500/10 px-4 py-2">
            <Zap className="h-4 w-4 text-orange-400" />
            <span className="text-sm font-medium text-orange-300">
              {activeProjects.length} sites running
            </span>
          </div>
        </div>

        {/* Mini progress bars */}
        {!isLoading && (
          <div className="mt-4 grid grid-cols-3 gap-3">
            {activeProjects.slice(0, 3).map(p => (
              <div key={String(p.id)} className="rounded-xl bg-gray-800/60 px-3 py-2">
                <div className="mb-1.5 flex items-center justify-between">
                  <span className="text-xs text-gray-300 truncate max-w-[110px]">{String(p.name ?? '').split(' ').slice(0, 2).join(' ')}</span>
                  <span className="text-xs font-bold text-orange-400">{Number(p.progress ?? 0)}%</span>
                </div>
                <div className="h-1.5 w-full rounded-full bg-gray-700">
                  <div className="h-full rounded-full bg-orange-500 transition-all" style={{ width: `${Number(p.progress ?? 0)}%` }} />
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* KPI Cards */}
      <div className="grid grid-cols-4 gap-4">
        {kpiCards.map((card, idx) => {
          const Icon = card.icon;
          return (
            <div key={idx} className="bg-gray-900 border border-gray-800 rounded-2xl p-5 hover:border-gray-700 transition-colors">
              <div className="flex items-center justify-between mb-3">
                <span className="text-xs font-medium text-gray-400">{card.label}</span>
                <div className={clsx(card.iconBg, 'h-9 w-9 rounded-xl flex items-center justify-center')}>
                  <Icon className={clsx('h-4 w-4', card.iconColor)} />
                </div>
              </div>
              <p className="text-2xl font-bold text-white">{card.value}</p>
              <div className="mt-1 flex items-center gap-1.5">
                {card.trend && (
                  <span className="text-xs font-medium text-green-400 flex items-center gap-0.5">
                    <TrendingUp className="h-3 w-3" />{card.trend}
                  </span>
                )}
                <span className="text-xs text-gray-500">{card.sub}</span>
              </div>
            </div>
          );
        })}
      </div>

      {/* Charts Row */}
      <div className="grid grid-cols-3 gap-4">
        {/* Revenue Bar Chart */}
        <div className="col-span-2 bg-gray-900 border border-gray-800 rounded-2xl p-5">
          <div className="flex items-center justify-between mb-4">
            <h3 className="text-sm font-semibold text-white">Revenue vs Costs (Last 7 Months)</h3>
            <button onClick={() => setModule('accounting')} className="flex items-center gap-1 text-xs text-orange-400 hover:text-orange-300">
              View full <ArrowRight className="h-3 w-3" />
            </button>
          </div>
          <ResponsiveContainer width="100%" height={220}>
            <BarChart data={MONTH_REVENUE} barSize={16}>
              <CartesianGrid strokeDasharray="3 3" stroke="#374151" vertical={false} />
              <XAxis dataKey="month" stroke="#6b7280" tick={{ fontSize: 11 }} />
              <YAxis stroke="#6b7280" tick={{ fontSize: 11 }} tickFormatter={v => `£${(v / 1000).toFixed(0)}K`} />
              <Tooltip
                contentStyle={{ backgroundColor: '#111827', border: '1px solid #374151', borderRadius: 8 }}
                formatter={(val: number) => [`£${val.toLocaleString()}`, '']}
              />
              <Legend iconType="circle" iconSize={8} wrapperStyle={{ fontSize: 11 }} />
              <Bar dataKey="revenue" fill="#f97316" radius={[4, 4, 0, 0]} name="Revenue" />
              <Bar dataKey="costs" fill="#4b5563" radius={[4, 4, 0, 0]} name="Costs" />
              <Bar dataKey="profit" fill="#22c55e" radius={[4, 4, 0, 0]} name="Profit" />
            </BarChart>
          </ResponsiveContainer>
        </div>

        {/* Project Status Donut */}
        <div className="bg-gray-900 border border-gray-800 rounded-2xl p-5">
          <h3 className="text-sm font-semibold text-white mb-4">Project Status</h3>
          {pieData.length > 0 ? (
            <ResponsiveContainer width="100%" height={200}>
              <PieChart>
                <Pie data={pieData} cx="50%" cy="50%" innerRadius={55} outerRadius={80} paddingAngle={3} dataKey="value">
                  {pieData.map((entry, i) => (
                    <Cell key={i} fill={STATUS_COLORS[entry.name] ?? '#6b7280'} />
                  ))}
                </Pie>
                <Tooltip
                  contentStyle={{ backgroundColor: '#111827', border: '1px solid #374151', borderRadius: 8 }}
                />
              </PieChart>
            </ResponsiveContainer>
          ) : (
            <div className="h-48 flex items-center justify-center text-sm text-gray-500">No data</div>
          )}
          <div className="mt-2 space-y-1">
            {Object.entries(statusCounts).map(([status, count]) => (
              <div key={status} className="flex items-center justify-between text-xs">
                <div className="flex items-center gap-2">
                  <div className="h-2 w-2 rounded-full" style={{ backgroundColor: STATUS_COLORS[status] ?? '#6b7280' }} />
                  <span className="text-gray-400 capitalize">{status.replace('_', ' ')}</span>
                </div>
                <span className="font-medium text-white">{count}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Bottom Row: Activity Feed + Quick Actions */}
      <div className="grid grid-cols-3 gap-4">
        {/* Recent Activity */}
        <div className="col-span-2 bg-gray-900 border border-gray-800 rounded-2xl p-5">
          <h3 className="text-sm font-semibold text-white mb-4">Recent Activity</h3>
          {recentActivity.length === 0 ? (
            <p className="text-sm text-gray-500 text-center py-6">No recent activity</p>
          ) : (
            <div className="space-y-3">
              {recentActivity.map((item, idx) => (
                <div key={idx} className="flex items-start gap-3 py-1.5 border-b border-gray-800 last:border-0">
                  <div className={clsx(item.dot, 'mt-1.5 h-2 w-2 rounded-full flex-shrink-0')} />
                  <div className="flex-1 min-w-0">
                    <p className="text-sm text-gray-300 truncate">{item.label}</p>
                  </div>
                  <span className="flex-shrink-0 flex items-center gap-1 text-xs text-gray-500">
                    <Clock className="h-3 w-3" />{item.timeLabel}
                  </span>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Safety Status + Quick Actions */}
        <div className="space-y-4">
          {/* Safety Banner */}
          <div className={clsx(
            'rounded-2xl border p-4',
            openIncidents === 0
              ? 'border-emerald-800/40 bg-emerald-900/20'
              : 'border-red-800/40 bg-red-900/20'
          )}>
            <div className="flex items-center gap-3">
              {openIncidents === 0 ? (
                <CheckCircle2 className="h-5 w-5 text-emerald-400 flex-shrink-0" />
              ) : (
                <AlertCircle className="h-5 w-5 text-red-400 flex-shrink-0" />
              )}
              <div>
                <p className="text-sm font-semibold text-white">
                  {openIncidents === 0 ? 'All clear — no open incidents' : `${openIncidents} open incident${openIncidents > 1 ? 's' : ''}`}
                </p>
                <p className={clsx('text-xs', openIncidents === 0 ? 'text-emerald-300' : 'text-red-300')}>
                  {openIncidents === 0 ? 'Safety record looking good' : 'Review required'}
                </p>
              </div>
            </div>
          </div>

          {/* Quick Actions */}
          <div className="bg-gray-900 border border-gray-800 rounded-2xl p-5">
            <h3 className="text-sm font-semibold text-white mb-3">Quick Navigation</h3>
            <div className="grid grid-cols-2 gap-2">
              {QUICK_ACTIONS.map((action, idx) => {
                const Icon = action.icon;
                return (
                  <button
                    key={idx}
                    onClick={() => { setModule(action.module); setActiveProject(null); }}
                    className={clsx('rounded-xl border p-3 flex flex-col items-center gap-1.5 transition-all text-center', action.bg)}
                  >
                    <Icon className={clsx('h-4 w-4', action.color)} />
                    <span className="text-xs font-medium text-white">{action.label}</span>
                  </button>
                );
              })}
            </div>
          </div>

          {/* Stats Summary */}
          <div className="bg-gray-900 border border-gray-800 rounded-2xl p-4 space-y-3">
            <h3 className="text-sm font-semibold text-white">Today's Summary</h3>
            {[
              { label: 'Total team', value: String(team.length), icon: HardHat },
              { label: 'Open RFIs', value: String(openRFIs), icon: MessageSquare },
              { label: 'Incidents open', value: String(openIncidents), icon: AlertCircle },
              { label: 'Reports today', value: String(reports.filter(r => String(r.date ?? '') === new Date().toISOString().split('T')[0]).length), icon: BarChart3 },
            ].map((stat, i) => {
              const Icon = stat.icon;
              return (
                <div key={i} className="flex items-center justify-between">
                  <div className="flex items-center gap-2">
                    <Icon className="h-3.5 w-3.5 text-gray-500" />
                    <span className="text-xs text-gray-400">{stat.label}</span>
                  </div>
                  <span className="text-xs font-bold text-white">{stat.value}</span>
                </div>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
}

